package main

import (
    "errors"
    "fmt"
    "os"
    "os/exec"
    "path/filepath"
    "regexp"
    "strings"
)

// Compliant: Validate and sanitize inputs
func compressFileSecure(filename string) error {
    // Validate filename
    if !isValidFilename(filename) {
        return errors.New("invalid filename")
    }

    // Use absolute paths to prevent path traversal
    absPath, err := filepath.Abs(filename)
    if err != nil {
        return err
    }

    // Ensure file exists and is within allowed directory
    if !isAllowedPath(absPath) {
        return errors.New("file path not allowed")
    }

    outputPath := absPath + ".tar.gz"

    // Use separate arguments instead of shell interpolation
    cmd := exec.Command("tar", "-czf", outputPath, absPath)
    return cmd.Run()
}

func isValidFilename(filename string) bool {
    // Only allow alphanumeric, dots, hyphens, and underscores
    matched, _ := regexp.MatchString(`^[a-zA-Z0-9._-]+$`, filename)
    return matched && !strings.Contains(filename, "..")
}

func isAllowedPath(path string) bool {
    allowedDir := "/var/app/data"
    absAllowedDir, _ := filepath.Abs(allowedDir)
    return strings.HasPrefix(path, absAllowedDir)
}

// Compliant: Use allowlists for search terms
var allowedSearchTerms = map[string]bool{
    "error": true,
    "warning": true,
    "info": true,
    "debug": true,
}

func searchFilesSecure(searchTerm string) ([]byte, error) {
    // Validate against allowlist
    if !allowedSearchTerms[searchTerm] {
        return nil, errors.New("search term not allowed")
    }

    // Use fixed log directory
    logDir := "/var/log/myapp"

    // Use separate arguments, not shell execution
    cmd := exec.Command("grep", "-r", searchTerm, logDir)
    return cmd.Output()
}

// Compliant: Parameterized execution with validation
func backupDatabaseSecure(dbName string) error {
    // Validate database name
    if !isValidDatabaseName(dbName) {
        return errors.New("invalid database name")
    }

    // Create secure output path
    outputPath := filepath.Join("/var/backups", dbName+".sql")

    // Use separate arguments
    cmd := exec.Command("mysqldump", "-u", "backup_user", dbName)

    // Redirect output to file securely
    outputFile, err := os.Create(outputPath)
    if err != nil {
        return err
    }
    defer outputFile.Close()

    cmd.Stdout = outputFile
    return cmd.Run()
}

func isValidDatabaseName(name string) bool {
    // Only allow alphanumeric and underscore
    matched, _ := regexp.MatchString(`^[a-zA-Z][a-zA-Z0-9_]*$`, name)
    return matched && len(name) <= 64
}

// Compliant: Use predefined command options
var allowedListOptions = map[string][]string{
    "detailed": {"-la"},
    "simple":   {"-l"},
    "hidden":   {"-a"},
}

func listFilesSecure(directory string, optionKey string) ([]byte, error) {
    // Validate directory
    if !isAllowedPath(directory) {
        return nil, errors.New("directory not allowed")
    }

    // Get predefined options
    options, exists := allowedListOptions[optionKey]
    if !exists {
        return nil, errors.New("invalid option")
    }

    // Build command with validated inputs
    args := append(options, directory)
    cmd := exec.Command("ls", args...)
    return cmd.Output()
}

// Compliant: Avoid shell execution entirely
type ImageProcessor struct {
    allowedOperations map[string][]string
}

func NewImageProcessor() *ImageProcessor {
    return &ImageProcessor{
        allowedOperations: map[string][]string{
            "resize_small": {"-resize", "200x200"},
            "resize_large": {"-resize", "800x600"},
            "grayscale":    {"-colorspace", "Gray"},
        },
    }
}

func (ip *ImageProcessor) ProcessImage(imagePath string, operationKey string) error {
    // Validate image path
    if !isValidImagePath(imagePath) {
        return errors.New("invalid image path")
    }

    // Get predefined operation
    operation, exists := ip.allowedOperations[operationKey]
    if !exists {
        return errors.New("operation not allowed")
    }

    outputPath := imagePath + "_processed.jpg"

    // Build command with validated parameters
    args := append(operation, imagePath, outputPath)
    cmd := exec.Command("convert", args...)
    return cmd.Run()
}

func isValidImagePath(path string) bool {
    // Check file extension
    ext := filepath.Ext(path)
    validExts := map[string]bool{".jpg": true, ".jpeg": true, ".png": true, ".gif": true}

    if !validExts[ext] {
        return false
    }

    // Ensure path is in allowed directory
    return isAllowedPath(path)
}
